def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            weight = 1 / (j ** 1.7)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.2
            elif j % 2 == 0:
                term *= 0.85
            else:
                term *= 0.95
            score += term
        if capacity < item * 1.1:
            score *= 1.5
        elif capacity < item * 1.3:
            score *= 1.2
        elif capacity < item * 1.6:
            score *= 1.05
        else:
            score *= 0.65
        mod3 = capacity % 3
        mod5 = capacity % 5
        mod7 = capacity % 7
        if mod3 == 0 and mod5 == 0:
            score -= 0.25
        elif mod3 == 0:
            score -= 0.1
        elif mod5 == 0:
            score += 0.25
        else:
            score += 0.1
        if mod7 == 0:
            score *= 0.9
        penalty = 0
        for k in range(1, 6):
            diff = capacity - item * k
            if diff < 0:
                penalty += 0.04 * k * abs(diff)
            else:
                penalty -= 0.015 * k * diff
            if k % 2 == 0 and diff < 0:
                penalty += 0.02 * k
        score += penalty
        if score < 0:
            score = 0
        if capacity > item * 2:
            for m in range(1, 4):
                if (capacity - item * m) % 4 == 0:
                    score *= 0.95
                else:
                    score *= 1.02
        priorities[i] = score
    return priorities
